const data = $input.first().json;
const idList = data.esearchresult.idlist;
if (!idList || idList.length === 0) return [];
return [{ json: { idString: idList.join(',') } }];

const articles = $input.first().json.PubmedArticleSet.PubmedArticle;
const results = [];
const articleArray = Array.isArray(articles) ? articles : [articles];

for (const item of articleArray) {
    if (!item || !item.MedlineCitation) continue;
    try {
        const article = item.MedlineCitation.Article;

        const titleRaw = article.ArticleTitle;
        const title = typeof titleRaw === 'string' ? titleRaw : (titleRaw._ || '无标题');

        let abstract = '无摘要';
        if (article.Abstract && article.Abstract.AbstractText) {
            const absRaw = article.Abstract.AbstractText;
            if (Array.isArray(absRaw)) {
                abstract = absRaw.map(a => {
                    if (typeof a === 'string') return a;
                    const label = (a.$ && (a.$.Label || a.$.NlmCategory))
                        ? '[' + (a.$.Label || a.$.NlmCategory) + '] ' : '';
                    return label + (a._ || '');
                }).filter(s => s.trim()).join('\n\n');
            } else if (typeof absRaw === 'string') {
                abstract = absRaw;
            } else if (absRaw._) {
                abstract = absRaw._;
            }
        }

        // 无摘要跳过
        if (!abstract || abstract === '无摘要' || abstract.length < 50) continue;

        const pmidRaw = item.MedlineCitation.PMID;
        const pmid = typeof pmidRaw === 'object' ? (pmidRaw._ || '') : String(pmidRaw);
        const link = 'https://pubmed.ncbi.nlm.nih.gov/' + pmid + '/';

        let pubDate = '';
        try {
            const pd = article.Journal.JournalIssue.PubDate;
            const year = pd.Year || '';
            const monthMap = {'Jan':'01','Feb':'02','Mar':'03','Apr':'04','May':'05','Jun':'06',
                              'Jul':'07','Aug':'08','Sep':'09','Oct':'10','Nov':'11','Dec':'12'};
            let month = pd.Month || '01';
            month = monthMap[month] || String(month).padStart(2, '0');
            const day = pd.Day ? String(pd.Day).padStart(2, '0') : '01';
            pubDate = year + '-' + month + '-' + day;
        } catch(e) { pubDate = ''; }

        let entrezDate = '';
        try {
            const history = item.PubmedData
                && item.PubmedData.History
                && item.PubmedData.History.PubMedPubDate;
            if (history) {
                const histArr = Array.isArray(history) ? history : [history];
                const entryRow = histArr.find(h => {
                    const ps = (h.$ && h.$.PubStatus) || h.PubStatus || '';
                    return ps === 'entrez';
                });
                if (entryRow) {
                    const ey = (Array.isArray(entryRow.Year) ? entryRow.Year[0] : entryRow.Year) || '';
                    const em = String((Array.isArray(entryRow.Month) ? entryRow.Month[0] : entryRow.Month) || '1').padStart(2, '0');
                    const ed = String((Array.isArray(entryRow.Day) ? entryRow.Day[0] : entryRow.Day) || '1').padStart(2, '0');
                    if (ey) entrezDate = ey + '-' + em + '-' + ed;
                }
            }
        } catch(e) { entrezDate = ''; }

        const journalName = (article.Journal && article.Journal.Title)
            ? article.Journal.Title : '';

        let firstAuthor = '';
        try {
            const authors = article.AuthorList.Author;
            const authorArr = Array.isArray(authors) ? authors : [authors];
            const a = authorArr[0];
            if (a) firstAuthor = (a.LastName || '') + (a.ForeName ? ' ' + a.ForeName : '');
        } catch(e) {}

        results.push({
            json: {
                Title: title, PubDate: pubDate, EntrezDate: entrezDate,
                Link: link, PMID: pmid, Abstract: abstract,
                JournalName: journalName, FirstAuthor: firstAuthor
            }
        });
    } catch(e) { continue; }
}
return results;

const staticData = $getWorkflowStaticData('global');
if (!staticData.processedPMIDs) staticData.processedPMIDs = [];

const allItems = $input.all();
const newItems = [];

for (const item of allItems) {
    const pmid = item.json.PMID || '';
    if (pmid && staticData.processedPMIDs.includes(pmid)) continue;
    newItems.push({ json: { ...item.json } });
}

const allPMIDs = allItems.map(i => i.json.PMID).filter(Boolean);
staticData.processedPMIDs = [...staticData.processedPMIDs, ...allPMIDs].slice(-500);

return newItems.length > 0 ? newItems : [];

const items = $input.all();
const originals = $('送入守门员').all();

return items.map((item, i) => {
    const orig = originals[i]?.json || {};
    let pass = false, reason = '';

    try {
        let content = item.json.text || '';
        content = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
        const fo = content.indexOf('{'), lc = content.lastIndexOf('}');
        if (fo !== -1 && lc !== -1) {
            const p = JSON.parse(content.substring(fo, lc + 1));
            pass = p.pass === true;
            reason = p.reason || '';
        }
    } catch(e) { pass = false; reason = '解析失败'; }

    return {
        json: { ...orig, gatekeeper_pass: pass, gatekeeper_reason: reason }
    };
});

const items = $input.all();
const allOriginals = $('字段映射1').all();

const results = [];
for (let i = 0; i < items.length; i++) {
    const item = items[i];
    const orig = allOriginals[i]?.json || {};

    let finalSummary = '', finalTitle = '', translatedAbstract = '', seoKeywords = '';
    try {
        const raw = item.json.output || item.json.text || '';
        const fo = raw.indexOf('{'), lc = raw.lastIndexOf('}');
        if (fo !== -1 && lc !== -1) {
            const p = JSON.parse(raw.substring(fo, lc + 1));
            if (p.summary)             finalSummary       = p.summary;
            if (p.translated_title)    finalTitle         = p.translated_title;
            if (p.translated_abstract) translatedAbstract = p.translated_abstract;
            if (p.seo_keywords)        seoKeywords        = p.seo_keywords;
        }
    } catch(e) {}

    results.push({
        json: {
            ...orig,
            is_relevant: true,
            summary: finalSummary,
            title: finalTitle || orig.original_title || '标题缺失',
            translated_abstract: translatedAbstract,
            seo_keywords: seoKeywords
        }
    });
}
return results;

const items = $input.all();
const results = [];

for (const item of items) {
    const d = item.json;
    const wpTitle    = d.title || d.original_title || '标题缺失';
    const sourceInfo = d.source_name || d.JournalName || 'PubMed';
    const link       = d.link || d.Link || '';

    let wpContent = '';
    if (d.translated_abstract) {
        wpContent += '<p>' + d.translated_abstract + '</p>\n\n';
    }
    wpContent += '<p>📎 来源：' + sourceInfo;
    if (link) {
        wpContent += ' | <a href="' + link + '" target="_blank" rel="noopener">查看原文</a>';
    }
    wpContent += '</p>';

    results.push({
        json: {
            wp_title:           wpTitle,
            wp_content:         wpContent,
            wp_excerpt:         d.summary || '',
            wp_seo_keywords:    d.seo_keywords || '',
            wp_seo_description: (d.summary || '').substring(0, 156),
            original_link:      link,
            source_name:        sourceInfo,
            summary:            d.summary || ''
        }
    });
}
return results;

